# models/legal_hold.py
from dataclasses import dataclass, field
from datetime import datetime, timezone
from typing import Optional
import json
from pathlib import Path

@dataclass
class LegalHold:
    hold_id: str
    case_reference: str
    custodian: str          # email of the legal contact responsible
    created_at: str
    applies_to: list[str]   # list of log store prefixes / bucket prefixes under hold
    released_at: Optional[str] = None
    notes: str = ""

    def is_active(self) -> bool:
        return self.released_at is None

    def covers(self, resource: str) -> bool:
        return any(resource.startswith(prefix) for prefix in self.applies_to)


HOLD_REGISTER_PATH = Path("config/legal-holds.json")


def load_holds() -> list[LegalHold]:
    if not HOLD_REGISTER_PATH.exists():
        return []
    data = json.loads(HOLD_REGISTER_PATH.read_text())
    return [LegalHold(**h) for h in data]


def is_on_hold(resource: str) -> bool:
    for hold in load_holds():
        if hold.is_active() and hold.covers(resource):
            return True
    return False

