# erasure/gdpr_erasure.py
import hashlib
import secrets
from datetime import datetime, timezone

# The user hash key is stored per-user in a key vault.
# When a user requests erasure, their key is deleted.
# Future log queries for that hash return nothing (key gone).
# Past log entries containing the old hash become orphaned — un-linkable.

class UserHashKeyVault:
    def __init__(self, vault_client):
        self._vault = vault_client

    def get_or_create_key(self, user_id: str) -> str:
        key_name = f"user-hash-key/{user_id}"
        try:
            return self._vault.read_secret(key_name)
        except KeyError:
            new_key = secrets.token_hex(32)
            self._vault.write_secret(key_name, new_key)
            return new_key

    def hash_user_id(self, user_id: str) -> str:
        key = self.get_or_create_key(user_id)
        return hashlib.sha256(f"{key}:{user_id}".encode()).hexdigest()[:16]

    def erase_user(self, user_id: str) -> dict:
        key_name = f"user-hash-key/{user_id}"
        try:
            self._vault.delete_secret(key_name)
            erased = True
        except KeyError:
            erased = False   # key already gone

        return {
            "user_id": user_id,
            "erased": erased,
            "erased_at": datetime.now(timezone.utc).isoformat(),
            "note": (
                "Hash key deleted. Existing log entries referencing previous hash "
                "are now un-linkable. Hot/warm tier entries will age out per policy. "
                "Cold tier entries remain but cannot be associated with this user."
            ),
        }

# erasure/physical_delete.py — hot and warm tier example
import boto3
from typing import Iterator

def list_objects_with_user_hash(
    bucket: str,
    prefix: str,
    user_hash: str,
    s3=None,
) -> Iterator[str]:
    if s3 is None:
        s3 = boto3.client("s3")
    paginator = s3.get_paginator("list_objects_v2")
    for page in paginator.paginate(Bucket=bucket, Prefix=prefix):
        for obj in page.get("Contents", []):
            # Check object tags for user_hash label
            tags_resp = s3.get_object_tagging(Bucket=bucket, Key=obj["Key"])
            tags = {t["Key"]: t["Value"] for t in tags_resp["TagSet"]}
            if tags.get("user_hash") == user_hash:
                yield obj["Key"]


def delete_user_objects(bucket: str, prefix: str, user_hash: str) -> int:
    s3 = boto3.client("s3")
    to_delete = list(list_objects_with_user_hash(bucket, prefix, user_hash, s3))
    if not to_delete:
        return 0

    batch = [{"Key": k} for k in to_delete]
    s3.delete_objects(Bucket=bucket, Delete={"Objects": batch, "Quiet": True})
    return len(to_delete)

# terraform/modules/audit_log_bucket/main.tf

resource "aws_s3_bucket" "audit_logs" {
  bucket = var.bucket_name

  # Object Lock must be enabled at bucket creation — cannot be added later
  object_lock_enabled = true

  tags = {
    data_classification = "audit"
    compliance          = "soc2,hipaa,gdpr"
    retention_policy    = "7yr"
    owner               = "security"
  }
}

resource "aws_s3_bucket_object_lock_configuration" "audit" {
  bucket = aws_s3_bucket.audit_logs.id

  rule {
    default_retention {
      mode  = "GOVERNANCE"   # GOVERNANCE allows override with explicit permission
      years = 7
    }
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "audit" {
  bucket = aws_s3_bucket.audit_logs.id

  rule {
    id     = "audit-tiering"
    status = "Enabled"

    transition {
      days          = 91
      storage_class = "GLACIER"
    }

    transition {
      days          = 2557   # 7 years
      storage_class = "DEEP_ARCHIVE"
    }

    expiration {
      days = 3650   # 10 years — hard limit beyond compliance floor
    }
  }
}

# Deny delete-object calls without legal-hold-release tag
resource "aws_s3_bucket_policy" "deny_delete" {
  bucket = aws_s3_bucket.audit_logs.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Sid       = "DenyDeleteWithoutHoldRelease"
      Effect    = "Deny"
      Principal = "*"
      Action    = ["s3:DeleteObject", "s3:DeleteObjectVersion"]
      Resource  = "${aws_s3_bucket.audit_logs.arn}/*"
      Condition = {
        StringNotEquals = {
          "s3:RequestObjectTag/legal-hold-status" = "released"
        }
      }
    }]
  })
}

#!/usr/bin/env python3
# scripts/validate-compliance-retention.py

import sys
import boto3

# Minimum retention days per data classification
COMPLIANCE_MINIMUMS = {
    "audit":   7 * 365,   # 7 years (HIPAA / GDPR)
    "app":     365,        # 12 months (SOC 2 / PCI)
    "infra":   365,        # 12 months (SOC 2)
    "metrics": 395,        # 13 months (finance)
}

def check_s3_bucket(s3, bucket: str, classification: str) -> list[str]:
    errors = []
    min_days = COMPLIANCE_MINIMUMS.get(classification)
    if min_days is None:
        return [f"Unknown classification '{classification}' on bucket '{bucket}'"]

    try:
        lc = s3.get_bucket_lifecycle_configuration(Bucket=bucket)
    except s3.exceptions.NoSuchLifecycleConfiguration:
        return [f"Bucket '{bucket}' has no lifecycle configuration"]

    expiry_days = None
    for rule in lc.get("Rules", []):
        expiry = rule.get("Expiration", {}).get("Days")
        if expiry:
            expiry_days = min(expiry_days, expiry) if expiry_days else expiry

    if expiry_days is None:
        errors.append(f"Bucket '{bucket}' has no expiration rule")
    elif expiry_days < min_days:
        errors.append(
            f"Bucket '{bucket}' expires in {expiry_days}d but "
            f"classification '{classification}' requires {min_days}d minimum"
        )
    return errors


BUCKETS = {
    "prod-audit-logs-immutable": "audit",
    "prod-app-logs":             "app",
    "prod-infra-logs":           "infra",
}

def main() -> int:
    s3 = boto3.client("s3")
    all_errors = []
    for bucket, classification in BUCKETS.items():
        all_errors.extend(check_s3_bucket(s3, bucket, classification))

    if all_errors:
        for e in all_errors:
            print(f"FAIL: {e}", file=sys.stderr)
        return 1

    print(f"OK: {len(BUCKETS)} buckets validated against compliance minimums")
    return 0

if __name__ == "__main__":
    sys.exit(main())
